category: "Preventive & Social Medicine",
subcategory: "01-epidemiology",
tags: ["PYQ", "NEET PG 2022"],
text: "Which of the following steps is not included in WHO's STEP approach?",
options: [{"id": "A", "text": "Therapeutic assessment", "is_correct": true}, {"id": "B", "text": "Physical assessment", "is_correct": false}, {"id": "C", "text": "Biochemical assessment", "is_correct": false}, {"id": "D", "text": "Behavioral assessment", "is_correct": false}],
explanation: "<img src=\"https://corebtr-assets-production.s3.ap-south-1.amazonaws.com/question_explanation/b0ac232e-2cac-4df6-a1e1-f5e2a067c586.jpg\" alt=\"Uploaded Image\">",
images: []
