explanation: "**Phases of Family Life Cycle**\n<img src=\"https://corebtr-assets-production.s3.ap-south-1.amazonaws.com/question_explanation/fa25f0e8-186c-4d51-8369-a0df21969804.jpg\" alt=\"Uploaded Image\">",
